          if (v instanceof ArrayBuffer) {
            // For arrays of files, use the corresponding filename from filenames array
            const fileFilename = filenames && filenames[i] ? filenames[i] : `${key}[${i}]`;
            formData.append(`${key}[${i}]`, new Blob([v]), fileFilename);
          } else {
            formData.append(`${key}[${i}]`, v);
          }
        });
      } else if (value instanceof ArrayBuffer) {
        // For single files, use the provided filename or fallback to the key name
        const fileFilename = filename || key;
        formData.append(key, new Blob([value]), fileFilename);
      } else {
        formData.append(key, value);
      }
    });

    return formData;
  }
}

import { HttpError } from '../error.js';
import { Request } from '../transport/request.js';
import { RequestFetchAdapter } from '../transport/request-fetch-adapter.js';
import { HttpResponse, RequestHandler } from '../types.js';

/**
 * Final handler in the request chain that executes the actual HTTP request.
 * Uses the configured HTTP client adapter (Fetch or Axios) to send the request.
 */
export class TerminatingHandler implements RequestHandler {
  /**
   * Executes the actual HTTP request using the configured client adapter.
   * @template T - The expected response data type
   * @param request - The HTTP request to execute
   * @returns A promise that resolves to the HTTP response
   */
  async handle<T>(request: Request): Promise<HttpResponse<T>> {
    return new RequestFetchAdapter<T>(request).send();
  }

  /**
   * Executes a streaming HTTP request using the configured client adapter.
   * @template T - The expected response data type for each chunk
   * @param request - The HTTP request to execute
   * @returns An async generator that yields HTTP responses
   */
  async *stream<T>(request: Request): AsyncGenerator<HttpResponse<T>> {
    yield* new RequestFetchAdapter<T>(request).stream();
  }
}

import { HttpError } from '../error.js';
import { HttpMetadata } from '../types.js';
import { Hook, HttpRequest, HttpResponse } from './hook.js';

/**
 * Default implementation of the Hook interface that provides pass-through behavior.
 * This hook can be extended to add custom logic for request/response interception.
 */
export class CustomHook implements Hook {
  /**
   * Called before an HTTP request is sent.
   * Default implementation returns the request unchanged.
   * @param request - The HTTP request to be sent
   * @param params - Additional custom parameters
   * @returns A promise that resolves to the unmodified request
   */
  public async beforeRequest(request: HttpRequest, params: Map<string, string>): Promise<HttpRequest> {
    return request;
  }

  /**
   * Called after a successful HTTP response is received.
   * Default implementation returns the response unchanged.
   * @param request - The original HTTP request
   * @param response - The HTTP response received
   * @param params - Additional custom parameters
   * @returns A promise that resolves to the unmodified response
   */
  public async afterResponse(
    request: HttpRequest,
    response: HttpResponse<any>,
    params: Map<string, string>,
  ): Promise<HttpResponse<any>> {
    return response;
  }

  /**
   * Called when an HTTP request results in an error.
   * Default implementation wraps the error response in an HttpError object.
   * @param request - The original HTTP request
   * @param response - The error response received
   * @param params - Additional custom parameters
   * @returns A promise that resolves to an HttpError object
   */
  public async onError(
    request: HttpRequest,
    response: HttpResponse<any>,
    params: Map<string, string>,
  ): Promise<HttpError> {
    return new HttpError(response.metadata, response.raw);
  }
}

/**
 * Standard HTTP methods supported by the SDK.
 */
type HttpMethod = 'CONNECT' | 'DELETE' | 'GET' | 'HEAD' | 'OPTIONS' | 'PATCH' | 'POST' | 'PUT' | 'TRACE';

/**
 * Represents an HTTP request with all its components.
 */
export interface HttpRequest {
  /** Base URL of the API endpoint */
  baseUrl: string;
  /** HTTP method for the request */
  method: HttpMethod;
  /** Request path (relative to base URL) */
  path: string;
  /** Request headers as key-value pairs */
  headers: Map<string, unknown>;
  /** Request body payload (optional) */
  body?: BodyInit;
  /** Signal to abort the request (optional) */
  abortSignal?: AbortSignal;
  /** Query string parameters */
  queryParams: Map<string, unknown>;
  /** Path parameters for URL templating */
  pathParams: Map<string, unknown>;
}

/**
 * Metadata about an HTTP response.
 */
interface HttpMetadata {
  /** HTTP status code */
  status: number;
  /** HTTP status text message */
  statusText: string;
  /** Response headers as key-value pairs */
  headers: Record<string, string>;
}

/**
 * Represents an HTTP response with typed data.
 * @template T - The type of the response data
 */
export interface HttpResponse<T> {
  /** Parsed response data (optional) */
  data?: T;
  /** Response metadata (status, headers, etc.) */
  metadata: HttpMetadata;
  /** Raw response object from the HTTP client */
  raw: ArrayBuffer;
}

/**
 * Represents an HTTP error response.
 */
export interface HttpError {
  /** Error message or description */
  error: string;
  /** Response metadata (status, headers, etc.) */
  metadata: HttpMetadata;
}

/**
 * Hook interface for intercepting and modifying HTTP requests and responses.
 * Allows custom logic to be executed at different stages of the request lifecycle.
 */
export interface Hook {
  /**
   * Called before an HTTP request is sent.
   * Allows modification of the request before execution.
   * @param request - The HTTP request to be sent
   * @param params - Additional custom parameters
   * @returns A promise that resolves to the potentially modified request
   */
  beforeRequest(request: HttpRequest, params: Map<string, string>): Promise<HttpRequest>;

  /**
   * Called after a successful HTTP response is received.
   * Allows processing or modification of the response.
   * @param request - The original HTTP request
   * @param response - The HTTP response received
   * @param params - Additional custom parameters
   * @returns A promise that resolves to the potentially modified response
   */
  afterResponse(
    request: HttpRequest,
    response: HttpResponse<any>,
    params: Map<string, string>,
  ): Promise<HttpResponse<any>>;

  /**
   * Called when an HTTP request results in an error.
   * Allows custom error handling and transformation.
   * @param request - The original HTTP request
   * @param response - The error response received
   * @param params - Additional custom parameters
   * @returns A promise that resolves to an error object
   */
  onError(request: HttpRequest, response: HttpResponse<any>, params: Map<string, string>): Promise<HttpError>;
}

import { HttpError } from '../error.js';
import { ThrowableError } from '../errors/throwable-error.js';
import { Hook } from '../hooks/hook.js';
import { Request } from '../transport/request.js';
import { TransportHookAdapter } from '../transport/transport-hook-adapter.js';
import { ErrorDefinition } from '../transport/types.js';
import { ContentType, HttpResponse, RequestHandler } from '../types.js';
import { getContentTypeDefinition } from '../utils/content-type.js';

/**
 * Request handler that invokes custom hooks before requests and after responses.
 * Enables request/response interception and custom error handling.
 */
export class HookHandler implements RequestHandler {
  /** Next handler in the chain */
  next?: RequestHandler;

  constructor(private readonly hook: Hook) {}

  /**
   * Handles a standard HTTP request with hook invocation.
   * Calls beforeRequest hook, processes the request, and calls afterResponse or onError hooks.
   * @template T - The expected response data type
   * @param request - The HTTP request to process
   * @returns A promise that resolves to the HTTP response
   * @throws Error if no next handler is set, or if error handling fails
   */
  async handle<T>(request: Request): Promise<HttpResponse<T>> {
    if (!this.next) {
      throw new Error('No next handler set in hook handler.');
    }

    const hook = new TransportHookAdapter<T>();

    const hookParams = this.getHookParams<T>(request);

    const nextRequest = await hook.beforeRequest(request, hookParams);

    const response = await this.next.handle<T>(nextRequest);

    if (response.metadata.status < 400) {
      return await hook.afterResponse(nextRequest, response, hookParams);
    }

    // Handle error responses
    const arrayBuffer = response.raw;

    const rawContentType = response.metadata.headers['content-type']?.toLocaleLowerCase() || '';
    const contentType = getContentTypeDefinition(rawContentType);
    const statusCode = response.metadata.status;

    const error = request.errors.find((error): error is ErrorDefinition => {
      return error.contentType === contentType && error.status === statusCode;
    });

    if (error) {
      const decodedBody = new TextDecoder().decode(arrayBuffer);
      const json = JSON.parse(decodedBody);
      new error.error((json as any)?.message || '', json).throw();
    }

    const decodedBody = new TextDecoder().decode(arrayBuffer);
    throw new HttpError(
      response.metadata,
      arrayBuffer,
      `Unexpected response body for error status.\nStatusCode: ${response.metadata.status}\nBody: ${decodedBody}`,
    );
  }

  /**
   * Handles a streaming HTTP request with hook invocation.
   * Calls beforeRequest hook and afterResponse/onError hooks for each chunk.
   * @template T - The expected response data type for each chunk
   * @param request - The HTTP request to process
   * @returns An async generator that yields HTTP responses
   * @throws Error if no next handler is set, or if error handling fails
   */
  async *stream<T>(request: Request): AsyncGenerator<HttpResponse<T>> {
    if (!this.next) {
      throw new Error('No next handler set in hook handler.');
    }

    const hook = new TransportHookAdapter<T>();

    const hookParams = this.getHookParams<T>(request);

    const nextRequest = await hook.beforeRequest(request, hookParams);

    const stream = this.next.stream<T>(nextRequest);

    for await (const response of stream) {
      if (response.metadata.status < 400) {
        yield await hook.afterResponse(nextRequest, response, hookParams);
      } else {
        throw await hook.onError(nextRequest, response, hookParams);
      }
    }
  }

  /**
   * Extracts hook parameters from the request configuration.
   * @template T - The response data type
   * @param request - The HTTP request
   * @returns A map of hook parameter names to values
   */
  private getHookParams<T>(_request: Request): Map<string, string> {
    const hookParams: Map<string, string> = new Map();
    return hookParams;
  }
}

import { Request } from '../transport/request.js';
import { HttpResponse, RequestHandler } from '../types.js';

/**
 * Chain of Responsibility pattern implementation for request handlers.
 * Manages a linked chain of handlers that process HTTP requests sequentially.
 */
export class RequestHandlerChain {
  /** Array of handlers in the chain */
  private readonly handlers: RequestHandler[] = [];

  /**
   * Adds a handler to the end of the chain.
   * Links the new handler to the previous one in the chain.
   * @param handler - The request handler to add
   */
  addHandler(handler: RequestHandler): void {
    if (this.handlers.length > 0) {
      const previousHandler = this.handlers[this.handlers.length - 1];
      previousHandler.next = handler;
    }
    this.handlers.push(handler);
  }

  /**
   * Executes the handler chain for a standard request.
   * @template T - The expected response data type
   * @param request - The HTTP request to process
   * @returns A promise that resolves to the HTTP response
   * @throws Error if no handlers are added to the chain
   */
  async callChain<T>(request: Request): Promise<HttpResponse<T>> {
    if (!this.handlers.length) {
      throw new Error('No handlers added to the chain');
    }

    return this.handlers[0].handle<T>(request);
  }

  /**
   * Executes the handler chain for a streaming request.
   * @template T - The expected response data type for each chunk
   * @param request - The HTTP request to process
   * @returns An async generator that yields HTTP responses
   * @throws Error if no handlers are added to the chain
   */
  async *streamChain<T>(request: Request): AsyncGenerator<HttpResponse<T>> {
    if (!this.handlers.length) {
      throw new Error('No handlers added to the chain');
    }

    yield* this.handlers[0].stream<T>(request);
  }
}

import { RequestHandlerChain } from './handlers/handler-chain.js';
import { HookHandler } from './handlers/hook-handler.js';
import { RequestValidationHandler } from './handlers/request-validation-handler.js';
import { ResponseValidationHandler } from './handlers/response-validation-handler.js';
import { RetryHandler } from './handlers/retry-handler.js';
import { TerminatingHandler } from './handlers/terminating-handler.js';
import { CustomHook } from './hooks/custom-hook.js';
import { Request } from './transport/request.js';
import { isRequestCursorPagination } from './transport/types.js';
import { CursorPaginatedHttpResponse, HttpResponse, PaginatedHttpResponse, SdkConfig } from './types.js';

/**
 * Core HTTP client for making API requests.
 * Manages request/response handling through a chain of handlers for validation, retry, hooks, and more.
 */
export class HttpClient {
  /** Chain of request handlers that process requests in sequence */
  private readonly requestHandlerChain = new RequestHandlerChain();

  /**
   * Creates a new HTTP client with configured request handlers.
   * @param config - SDK configuration including base URL and authentication
   * @param hook - Optional custom hook for request/response interception
   */
  constructor(private config: SdkConfig, hook = new CustomHook()) {
    this.requestHandlerChain.addHandler(new ResponseValidationHandler());
    this.requestHandlerChain.addHandler(new RequestValidationHandler());
    this.requestHandlerChain.addHandler(new RetryHandler());
    this.requestHandlerChain.addHandler(new HookHandler(hook));
    this.requestHandlerChain.addHandler(new TerminatingHandler());
  }

  /**
   * Executes a standard HTTP request.
   * @template T - The expected response data type
   * @param request - The HTTP request to execute
   * @returns A promise that resolves to the HTTP response
   */
  call<T>(request: Request): Promise<HttpResponse<T>> {
    return this.requestHandlerChain.callChain(request);
  }

  /**
   * Executes a streaming HTTP request that yields responses incrementally.
   * @template T - The expected response data type for each chunk
   * @param request - The HTTP request to execute
   * @returns An async generator that yields HTTP responses
   */
  async *stream<T>(request: Request): AsyncGenerator<HttpResponse<T>> {
    yield* this.requestHandlerChain.streamChain(request);
  }

  /**
   * Executes a paginated HTTP request and extracts the page data from the response.
   * @template FullResponse - The complete response type from the API
   * @template Page - The type of a single page of data
   * @param request - The paginated HTTP request to execute
   * @returns A promise that resolves to the paginated HTTP response
   * @throws Error if the response contains no data to paginate through
   */
  public async callPaginated<FullResponse, Page>(request: Request<Page>): Promise<PaginatedHttpResponse<Page>> {
    const response = await this.call<FullResponse>(request as any);

    if (!response.data) {
      throw new Error('no response data to paginate through');
    }

    const page = this.getPage<FullResponse, Page>(request, response.data);

    return {
      ...response,
      data: page,
    };
  }

  /**
   * Executes a cursor-paginated HTTP request and extracts both page data and the next cursor.
   * @template FullResponse - The complete response type from the API
   * @template Page - The type of a single page of data
   * @param request - The cursor-paginated HTTP request to execute
   * @returns A promise that resolves to the cursor-paginated HTTP response with next cursor
   * @throws Error if the response contains no data to paginate through
   */
  public async callCursorPaginated<FullResponse, Page>(
    request: Request<Page>,
  ): Promise<CursorPaginatedHttpResponse<Page>> {
    const response = await this.call<FullResponse>(request as any);

    if (!response.data) {
      throw new Error('no response data to paginate through');
    }

    const page = this.getPage<FullResponse, Page>(request, response.data);
    const nextCursor = this.getNextCursor<FullResponse, Page>(request, response.data);

    return {
      ...response,
      data: page,
      nextCursor,
    };
  }

  /**
   * Updates the base URL for all subsequent requests.
   * @param url - The new base URL to use
   */
  setBaseUrl(url: string): void {
    this.config.baseUrl = url;
  }

  /**
   * Updates the SDK configuration.
   * @param config - The new SDK configuration
   */
  setConfig(config: SdkConfig): void {
    this.config = config;
  }

  /**
   * Extracts page data from a full API response using the configured pagination path.
   * @template FullResponse - The complete response type from the API
   * @template Page - The type of a single page of data
   * @param request - The request containing pagination configuration
   * @param data - The full response data to extract the page from
   * @returns The extracted and parsed page data
   * @throws Error if pagination is not configured or page extraction fails
   */
  private getPage<FullResponse, Page>(request: Request<Page>, data: FullResponse): Page {
    if (!request.pagination) {
      throw new Error('getPage called for request without pagination property');
    }

    let curr: any = data;
    for (const segment of request.pagination.pagePath || []) {
      curr = curr[segment];
    }

    const page = request.pagination.pageSchema?.parse(curr);
    if (!page) {
      throw new Error(
        `error getting page data. Curr: ${JSON.stringify(curr)}. PagePath: ${
          request.pagination.pagePath
        }. Data: ${JSON.stringify(data)}`,
      );
    }
    return page;
  }

  /**
   * Extracts the next cursor from a full API response for cursor-based pagination.
   * @template FullResponse - The complete response type from the API
   * @template Page - The type of a single page of data
   * @param request - The request containing cursor pagination configuration
   * @param data - The full response data to extract the cursor from
   * @returns The next cursor string, null if no more pages, or undefined if not cursor pagination
   */
  private getNextCursor<FullResponse, Page>(request: Request<Page>, data: FullResponse): string | null | undefined {
    if (!isRequestCursorPagination(request.pagination)) {
      return undefined;
    }

    let curr: any = data;
    for (const segment of request.pagination.cursorPath) {
      if (curr === null || curr === undefined) {
        return null;
      }
      curr = curr[segment];
    }

    return request.pagination.cursorSchema?.parse(curr) ?? null;
  }
}

